insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:fd3022aa', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Ransomware — locking a victim out of their own files", "reading": "<h4>Encrypts first, then demands payment</h4>\n<ul>\n<li><strong>Ransomware</strong> is malware that <strong>encrypts</strong> the victim''s files, scrambling them using a key that only the attacker holds.</li>\n<li>Once the files are encrypted, the victim can no longer open or use them — the attacker then demands a <strong>ransom payment</strong> (often in cryptocurrency) in exchange for the decryption key needed to unlock the files again.</li>\n<li>The files are not deleted or stolen in the usual sense — they still exist on the victim''s computer, just locked. Paying the ransom is never guaranteed to actually restore access, which is why businesses are advised to keep secure backups instead of relying on payment.</li>\n</ul>", "question": "What does ransomware specifically do to a victim''s files?", "options": ["It permanently deletes every file stored on the infected computer", "It encrypts the files and demands payment for the key to unlock them", "It slowly and permanently corrupts each individual file until none of them will open properly", "It copies every file onto a hidden folder on the same hard drive"]}'::jsonb, '{"answer": 1, "explain": "Ransomware''s defining feature is encryption plus a ransom demand — the files still exist, but the victim cannot access them without the attacker''s key."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:31f51abb', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Spyware and keyloggers — watching in secret", "reading": "<h4>Designed to go unnoticed</h4>\n<ul>\n<li><strong>Spyware</strong> is malware that secretly monitors a user''s activity — which websites they visit, what files they open, even what is shown on their screen — and sends that information back to an attacker.</li>\n<li>A <strong>keylogger</strong> is a specific type of spyware that records every key a user presses. Because it captures exactly what is typed, a keylogger is especially effective at stealing <strong>passwords</strong> and other sensitive text the moment the victim types it in.</li>\n<li>Both are dangerous specifically because they are hard to notice — unlike ransomware, which announces itself with a ransom demand, spyware works best when the victim has no idea it is there at all.</li>\n</ul>", "question": "What is a keylogger specifically designed to record?", "options": ["Every key a user presses on their keyboard, including passwords", "The total number of hours a computer has been switched on", "How many files are currently saved on the computer''s hard drive", "The exact temperature of the computer''s processor over time"]}'::jsonb, '{"answer": 0, "explain": "A keylogger records keystrokes — that means it can capture passwords, messages and other sensitive text exactly as the victim types them."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:362bcd22', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "What is social engineering, and why do people matter so much?", "reading": "<h4>Attacking the person, not the software</h4>\n<ul>\n<li><strong>Social engineering</strong> means manipulating a PERSON, rather than exploiting a weakness in software, into revealing information or breaking normal security procedures.</li>\n<li>It works because people can be trusting, busy, polite, or afraid of getting into trouble — an attacker exploits exactly those very human instincts.</li>\n<li>This is why people are often called <strong>\"the weakest link\"</strong> in security: even the strongest encryption, firewall or password policy is useless if a person can simply be talked into handing over access voluntarily.</li>\n</ul>", "question": "What does a social engineering attack primarily target?", "options": ["A weakness in a website''s encryption algorithm", "A person, by manipulating them into giving up information or access", "A gap in a network''s physical cabling", "An out-of-date version of an operating system that has never been patched or updated"]}'::jsonb, '{"answer": 1, "explain": "Social engineering bypasses technical security entirely by targeting a person''s trust, habits or fear — not a flaw in the software itself."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:0d5cd2ae', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Phishing — the most common social engineering attack", "reading": "<h4>Fake messages from a ''trusted'' source</h4>\n<ul>\n<li><strong>Phishing</strong> uses fake emails, text messages or websites that <strong>impersonate a trusted organisation</strong> — a bank, a delivery company, a school, an online shop — to trick the victim.</li>\n<li>The goal is usually to get the victim to click a malicious link, download an infected attachment, or type their username, password or card details directly into a fake login page.</li>\n<li>Common warning signs: an urgent or threatening tone (\"your account will be closed\"), a sender address that looks almost right but isn''t, generic greetings (\"Dear Customer\"), and links that don''t quite match the real organisation''s website.</li>\n</ul>", "question": "What is phishing?", "options": ["Automatically guessing thousands of different password combinations very quickly using software", "Fake messages that impersonate a trusted organisation to trick a victim", "Physically watching someone type their password over their shoulder", "Flooding a website with traffic so genuine users cannot access it"]}'::jsonb, '{"answer": 1, "explain": "Phishing is a type of social engineering built entirely around impersonating a trusted sender to trick the victim into acting."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:0125ad30', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Blagging and shouldering — two more social engineering tricks", "reading": "<h4>Blagging (pretexting) — inventing a story</h4>\n<ul>\n<li><strong>Blagging</strong>, also called pretexting, means inventing a false scenario — a \"pretext\" — to persuade a victim into handing over information or access. For example, an attacker phones pretending to be from the IT department and asks a member of staff to \"confirm\" their password.</li>\n</ul>\n<h4>Shouldering (shoulder surfing) — watching, not talking</h4>\n<ul>\n<li><strong>Shouldering</strong> means simply watching over someone''s shoulder as they type a password, PIN or other sensitive information — at an ATM, on a laptop on a train, or at a login screen.</li>\n<li>It requires no technical skill at all, just observation, which makes it easy to defend against (shielding the keypad, being aware of who is nearby) but easy to fall for if a victim isn''t paying attention.</li>\n</ul>", "question": "An attacker phones an employee, pretends to be from the company''s IT support team, and persuades them to reveal their password. What is this an example of?", "options": ["Shouldering", "Blagging (pretexting)", "A brute-force attack", "A denial of service attack"]}'::jsonb, '{"answer": 1, "explain": "Inventing a false scenario — posing as IT support — to talk a victim out of information is exactly what blagging (pretexting) means."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:ca513ccd', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Brute-force attacks — guessing at speed", "reading": "<h4>Trying every possible combination</h4>\n<ul>\n<li>A <strong>brute-force attack</strong> uses software to automatically try huge numbers of possible password combinations, one after another, until it finds the one that works.</li>\n<li>It doesn''t rely on tricking a person at all, unlike social engineering — it is a purely technical attack on the login system itself.</li>\n<li>A short, simple password has far fewer possible combinations, so it can be cracked quickly. A long password mixing upper/lower case letters, numbers and symbols has vastly more possible combinations, making the attack take far longer — often long enough to be impractical.</li>\n<li>Systems can defend against brute-force attacks by locking an account after a small number of failed attempts, or by slowing down each login attempt.</li>\n</ul>", "question": "What does a brute-force attack do?", "options": ["It tricks a victim into revealing their password directly", "It automatically tries huge numbers of password combinations until one works", "It floods a login page with an overwhelming amount of traffic so that nobody at all can access it", "It secretly records every key a victim presses while they type"]}'::jsonb, '{"answer": 1, "explain": "A brute-force attack is a purely automated, technical guessing attack — it does not involve tricking the victim or flooding a server."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:c58772e9', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Denial of Service and DDoS — making a service unavailable", "reading": "<h4>DoS: flooding, not stealing</h4>\n<ul>\n<li>A <strong>Denial of Service (DoS)</strong> attack floods a server with an overwhelming number of requests, using up its resources until it can no longer respond to genuine users.</li>\n<li>Crucially, a DoS attack does <strong>NOT</strong> steal, read or change any data — the goal is purely to make a service <strong>unavailable</strong>, not to break into it.</li>\n</ul>\n<h4>DDoS: the same idea, from many directions at once</h4>\n<ul>\n<li>A <strong>Distributed</strong> Denial of Service (DDoS) attack is the same idea, but the flood of traffic comes from <strong>many different computers at once</strong> — usually a <strong>botnet</strong>, a large network of computers that have already been infected with malware and are being secretly controlled by the attacker.</li>\n<li>A DDoS attack is much harder to stop than a single-source DoS attack, because the traffic arrives from thousands of different addresses simultaneously — blocking one source does nothing, since traffic keeps arriving from all the others.</li>\n</ul>", "question": "What is the main purpose of a Denial of Service attack?", "options": ["To read, copy and secretly transfer sensitive data stored on the target server", "To make a server or service unavailable to its genuine users", "To secretly install spyware onto the target''s computer", "To trick a specific employee into revealing their password"]}'::jsonb, '{"answer": 1, "explain": "A DoS/DDoS attack is about availability, not data — it floods a service so genuine users cannot use it, without stealing or altering anything."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:bd6c44c4', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Data interception and theft", "reading": "<h4>Catching data as it travels</h4>\n<ul>\n<li><strong>Data interception</strong> means capturing data while it is travelling across a network, rather than attacking the computer that stores it — sometimes called <strong>packet sniffing</strong> or eavesdropping.</li>\n<li>This is a particular risk on <strong>unsecured (unencrypted) networks</strong>, such as open public Wi-Fi in a café or airport, where data can travel in a form an attacker can simply read.</li>\n<li>Intercepted data might include login details, card or payment information, or private messages — anything the victim sends while connected.</li>\n<li>Encrypting data before it is sent, so it looks scrambled to anyone intercepting it, is the main defence — which is why sites using HTTPS are considered much safer for entering sensitive information than ones that don''t.</li>\n</ul>", "question": "Why is sending sensitive data over an unsecured public Wi-Fi network risky?", "options": ["Public Wi-Fi automatically shares your files with every other connected device", "An attacker can more easily intercept and read data as it travels across the network", "Unsecured networks can physically damage any device that attempts to connect to them at all", "Public Wi-Fi routers can only be used by one device at any given time"]}'::jsonb, '{"answer": 1, "explain": "Without encryption, data travelling across the network can be captured (''sniffed'') and read directly by anyone intercepting it."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:90d5e032', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "SQL injection — attacking a database through an input box", "reading": "<h4>Typing code where data was expected</h4>\n<ul>\n<li>Many websites store information — usernames, orders, product details — in a <strong>database</strong>, and use a language called <strong>SQL</strong> to read from and write to it.</li>\n<li>A <strong>SQL injection</strong> attack means typing malicious SQL code into a website''s input box, such as a login box or a search box, instead of the data the box was expecting.</li>\n<li>If the website doesn''t check its input properly, that malicious code gets passed straight into the database''s real command — letting the attacker <strong>view</strong>, <strong>change</strong> or <strong>delete</strong> data they should never see, or even log in without knowing a real password at all.</li>\n</ul>", "question": "What does a SQL injection attack involve?", "options": ["Flooding a database server with an enormous, continuous number of requests all at once", "Entering malicious SQL code into a website''s input box to attack its database", "Physically stealing the hard drive that a database is stored on", "Guessing a database administrator''s password using automated software"]}'::jsonb, '{"answer": 1, "explain": "SQL injection specifically exploits an input box that doesn''t check its data properly, letting malicious SQL code reach the real database command."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:82063f0c', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Why people and poor policy really are the weakest link", "reading": "<h4>Technology can only do so much</h4>\n<ul>\n<li>A business can install the best anti-malware, firewalls and encryption available — and still be compromised, because so many attacks target <strong>people</strong> and <strong>policy</strong> rather than the technology itself.</li>\n<li>Common weak points: <strong>weak or reused passwords</strong> that a brute-force attack can crack quickly; <strong>unpatched (out-of-date) software</strong> that still has known vulnerabilities a worm or attacker can exploit; and a lack of <strong>user access levels</strong>, meaning any single compromised account can reach far more data than it should.</li>\n<li>This is exactly why social engineering attacks like phishing remain so effective: no software flaw is required at all if a person can simply be persuaded to hand over what an attacker needs.</li>\n<li>This topic sets up the next one directly — <strong>1.4.2</strong> covers the specific defences (passwords, access levels, firewalls, training and more) that exist to close each of these weak points.</li>\n</ul>", "question": "Why can a business with strong technical security still be successfully attacked?", "options": ["Because firewalls and anti-malware software automatically stop working properly after about one year", "Because attacks like social engineering target people and policy, not just technology", "Because encryption always slows a network down too much to be practical", "Because antivirus software cannot be installed on more than one computer"]}'::jsonb, '{"answer": 1, "explain": "Weak passwords, unpatched software and susceptible people all create openings that no amount of purely technical security can close on its own."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:misc:d3f30226', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a virus and a worm are basically the same thing because both ''infect'' a computer.</p><p><strong>✅ The correct idea:</strong> A <strong>virus</strong> attaches to a file and only spreads once a user RUNS that infected file — it needs human action. A <strong>worm</strong> is fully self-replicating: it spreads across a network by itself, with no user action needed at all. That difference — needs the user, or doesn''t — is the exam''s favourite trap on this pair.</p>", "question": "What is the key difference between a virus and a worm?", "options": ["A virus only affects mobile devices, while a worm only affects desktop computers", "A virus needs the user to run an infected file; a worm spreads by itself", "A worm can be removed by antivirus software, but a virus cannot", "A virus always demands a ransom payment, while a worm never does"]}'::jsonb, '{"answer": 1, "explain": "A virus depends on the user running an infected host file; a worm spreads across a network entirely on its own."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:misc:fdf49497', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing a trojan copies itself onto other files and spreads like a virus, because it''s ''in the malware family''.</p><p><strong>✅ The correct idea:</strong> A <strong>trojan</strong> does NOT self-replicate. It disguises itself as software the user actually WANTS and installs willingly — a free game, a ''useful'' tool. The trick is in the disguise, not in copying itself onto other files.</p>", "question": "Why doesn''t a trojan need to copy itself onto other files to spread?", "options": ["Because it relies on the user willingly installing it, believing it is wanted software", "Because it can only ever infect a single computer before being destroyed immediately afterwards", "Because trojans are always removed automatically within a few minutes", "Because trojans only exist as physical malware on USB sticks"]}'::jsonb, '{"answer": 0, "explain": "A trojan''s method is deception, not replication — the victim installs it themselves because it looks like something they want."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:misc:5c9479e4', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming ransomware just hides or deletes a victim''s files.</p><p><strong>✅ The correct idea:</strong> Ransomware specifically <strong>encrypts</strong> the victim''s files, scrambling them with a key only the attacker holds, then demands a ransom payment in exchange for that key. The files still exist — they are locked, not gone — though there is no guarantee paying gets them back.</p>", "question": "What actually happens to a victim''s files during a ransomware attack?", "options": ["They are permanently and irreversibly deleted from every location on the computer", "They are encrypted, so they still exist but cannot be opened without a key", "They are copied to a public website for anyone to view", "They are automatically backed up to a secure server"]}'::jsonb, '{"answer": 1, "explain": "Ransomware locks files using encryption — the files are not deleted, but they cannot be used without the attacker''s decryption key."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:misc:955839fb', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking social engineering means hacking into a system using code.</p><p><strong>✅ The correct idea:</strong> Social engineering has nothing to do with exploiting software — it means manipulating a PERSON into handing over information or access voluntarily, using a fake phone call, email or pretext. It is called ''the weakest link'' precisely because these tricks bypass technical security altogether.</p>", "question": "Why is social engineering not considered a technical (software-based) attack?", "options": ["Because it always requires very expensive, specialist hacking equipment to carry out successfully", "Because it works by manipulating a person, not by exploiting a flaw in software", "Because it can only be carried out over a telephone, never online", "Because social engineering attacks are illegal in every country in the world"]}'::jsonb, '{"answer": 1, "explain": "Social engineering succeeds by tricking a human being, so it bypasses technical defences completely — no software vulnerability is required."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:misc:ca96f55e', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing a Denial of Service attack steals or damages the data on a server.</p><p><strong>✅ The correct idea:</strong> A DoS attack does not touch the data at all — it floods the server with so many requests that it cannot respond to genuine users. The goal is to make a service UNAVAILABLE, not to read, copy or change anything stored on it.</p>", "question": "What does a Denial of Service attack actually achieve if it succeeds?", "options": ["It quietly steals and copies the login details of every user who happens to visit the site", "It makes the service unavailable to genuine users, without touching the data", "It quietly rewrites the data stored in the server''s database", "It installs ransomware onto every device that connects to the server"]}'::jsonb, '{"answer": 1, "explain": "A DoS attack''s entire goal is denying access — it overwhelms the server''s resources rather than interacting with the data stored on it."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:misc:bd95f5f5', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming SQL injection is a network-based attack, like intercepting data as it travels.</p><p><strong>✅ The correct idea:</strong> SQL injection targets a website''s <strong>database</strong> through an input field, such as a login box, not the network connection. The attacker types malicious SQL code instead of a normal username, tricking the database into running a command it shouldn''t.</p>", "question": "What does a SQL injection attack actually target?", "options": ["Data as it travels across a network connection", "A website''s database, through an input box such as a login or search field", "The physical cabling and hardware connecting a server directly to the internet", "A user''s keyboard, by recording every key they press"]}'::jsonb, '{"answer": 1, "explain": "SQL injection exploits a website input field that fails to check its data properly, letting malicious code reach the real database command."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tips:aef4eed5', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tips', 'mcq', 1, '{"readingTitle": "explain — Command-word ladder: a 3-mark ''Describe how a worm spreads''", "reading": "<p>A typical question: <em>\"Describe how a worm is able to spread from one computer to another across a network.\"</em> [3 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"A worm is a type of virus that spreads to other computers.\"</p>\n<ul>\n<li>Calling a worm \"a type of virus\" is itself a factual error, and nothing about the MECHANISM of spreading is explained.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"A worm copies itself and spreads to other computers.\"</p>\n<ul>\n<li>Technically true, but far too vague for 3 marks. It doesn''t say HOW it spreads (across a network) or that it needs no user action — the two facts that actually earn the extra marks.</li>\n</ul>\n\n<p><strong>✅ 3 marks:</strong> \"A worm is able to make copies of itself <strong>(1)</strong>. It spreads across a network entirely by itself, without needing a user to open a file or take any action <strong>(1)</strong>. It typically does this by exploiting a weakness in software or in the network to move from one computer to the next <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters:</strong> \"Describe\" at 3 marks nearly always wants a chain of separate, specific facts — not one vague sentence repeated in different words. Naming the mechanism (self-replication), the key distinguishing detail (no user action) and how it actually moves (exploiting a weakness) is what separates 1 mark from full marks.</p>", "question": "A student writes only ''A worm copies itself and spreads to other computers'' for this 3-mark question. What is most likely missing for full marks?", "options": ["Nothing at all — the answer already explains the full spreading mechanism perfectly clearly", "The detail that it spreads without user action, and how it moves across the network", "A diagram showing the worm''s binary code in full", "The exact date the first computer worm was ever created"]}'::jsonb, '{"answer": 1, "explain": "The answer is too vague — it needs the specific facts that a worm needs no user action and typically exploits a weakness to move between computers."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tips:53f3b20b', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tips', 'mcq', 1, '{"readingTitle": "tip — Telling virus, worm and trojan apart under exam pressure", "reading": "<p>These three are constantly mixed up under exam pressure because they all \"spread\" or \"infect\" — but each one is defined by ONE precise, testable detail.</p>\n\n<p><strong>Ask these three questions, in order:</strong></p>\n<ul>\n<li><strong>1. Does it need the user to run an infected file before it does anything?</strong> If yes → it''s a <strong>virus</strong>.</li>\n<li><strong>2. Does it spread across a network completely on its own, with no user action at all?</strong> If yes → it''s a <strong>worm</strong>.</li>\n<li><strong>3. Does it disguise itself as wanted software, and NOT copy itself onto other files?</strong> If yes → it''s a <strong>trojan</strong>.</li>\n</ul>\n\n<p><strong>Worked example:</strong> \"Malware spreads across a school''s network overnight without anyone opening a single file.\" → Question 2 answers yes immediately: this is a <strong>worm</strong>, because it needed no user action at all.</p>\n\n<p>Ransomware and spyware are usually easier to spot because they name their OWN effect directly — \"encrypts files and demands payment\" is always ransomware; \"secretly records what the user does\" is always spyware.</p>", "question": "A piece of malware only starts working once an employee opens an infected email attachment. Using the three-question method, what is it most likely to be?", "options": ["A worm, since malware always spreads across networks", "A virus, since it depends on the user running the infected file", "Ransomware, since all malware eventually asks for a payment of some kind", "A DDoS attack, since it affects more than one computer"]}'::jsonb, '{"answer": 1, "explain": "Needing the user to open (run) an infected file before anything happens is the defining test for a virus, not the other options."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tips:8d1508a0', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — The 8-mark ''Discuss'' ladder: weighing up more than one threat", "reading": "<p>An 8-mark \"discuss\" question on threats always gives you several bullet points to structure your answer around, and always rewards WEIGHING UP more than one threat or factor, not just describing them one after another.</p>\n\n<p><strong>A reliable structure (~10–12 minutes):</strong></p>\n<ul>\n<li><strong>1. Explain the mechanism</strong> of each relevant threat — HOW it actually works, in your own words.</li>\n<li><strong>2. Follow each mechanism through to a real consequence</strong> for the specific scenario in the question (lost data, downed website, stolen money, damaged reputation) — a factor → effect → consequence chain, not just a one-word label.</li>\n<li><strong>3. Weigh the threats against each other</strong> — which is more likely, more costly, or more damaging for THIS business, and why? This comparison step is what separates a Band 2 answer from a Band 3 answer.</li>\n<li><strong>4. Reach a separate, justified conclusion</strong> — don''t let your final recommendation just repeat what you already said; add a clear \"therefore…\" sentence.</li>\n</ul>\n\n<p><strong>The band descriptors, in plain English:</strong></p>\n<ul>\n<li><strong>Band 3 (6–8 marks):</strong> thorough, accurate knowledge applied directly to the scenario, multiple threats properly weighed against each other, clear structure, justified conclusion.</li>\n<li><strong>Band 2 (3–5 marks):</strong> generally accurate but a bit generic or one-sided; most bullet points covered but the threats aren''t really compared against each other.</li>\n<li><strong>Band 1 (1–2 marks):</strong> basic, unsupported statements with little real explanation or application to the scenario given.</li>\n</ul>", "question": "What is most likely to separate a Band 3 (top-band) answer from a Band 2 answer on an 8-mark ''discuss the threats'' question?", "options": ["Using noticeably longer and more grammatically complicated sentences throughout the whole answer", "Explicitly weighing the threats against each other, not just describing them separately", "Naming as many different technical terms as possible, in any order", "Writing the answer in bullet points instead of full sentences"]}'::jsonb, '{"answer": 1, "explain": "Top-band ''discuss'' answers actively compare and weigh up the threats against each other and the scenario — description alone caps the mark in the middle band."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:fib:76dfb366', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'fib', 'fib', 1, '{"question": "A _____ attaches itself to a file or program and can only spread once a user runs that infected file.", "blankOptions": {"B1": ["spyware", "worm", "virus", "brute-force"]}}'::jsonb, '{"blanks": {"B1": "virus"}}'::jsonb),
