('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:4f11d5df', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Malware”?", "options": ["Software deliberately written to damage, disrupt or gain unauthorised access to a system", "Self-replicating malware that spreads across a network by itself, without any user action", "Automatically trying huge numbers of password combinations until the correct one is found", "Capturing data as it travels across a network, especially an unsecured one"]}'::jsonb, '{"answer": 0, "explain": "“Malware” means: Software deliberately written to damage, disrupt or gain unauthorised access to a system"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:51d37643', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Virus”?", "options": ["Software deliberately written to damage, disrupt or gain unauthorised access to a system", "Manipulating a person, rather than a system, into revealing information or breaking security procedures", "Attaches itself to a file or program and spreads when a user runs the infected host file", "Malware disguised as legitimate, wanted software that a user installs willingly; does not self-replicate"]}'::jsonb, '{"answer": 2, "explain": "“Virus” means: Attaches itself to a file or program and spreads when a user runs the infected host file"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:7360a630', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Worm”?", "options": ["Self-replicating malware that spreads across a network by itself, without any user action", "Malware disguised as legitimate, wanted software that a user installs willingly; does not self-replicate", "Flooding a server with traffic so that it cannot respond to genuine users'' requests", "Manipulating a person, rather than a system, into revealing information or breaking security procedures"]}'::jsonb, '{"answer": 0, "explain": "“Worm” means: Self-replicating malware that spreads across a network by itself, without any user action"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:f346c361', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trojan”?", "options": ["Capturing data as it travels across a network, especially an unsecured one", "Flooding a server with traffic so that it cannot respond to genuine users'' requests", "Malware disguised as legitimate, wanted software that a user installs willingly; does not self-replicate", "Fake emails, texts or websites that impersonate a trusted organisation to trick a user into revealing details"]}'::jsonb, '{"answer": 2, "explain": "“Trojan” means: Malware disguised as legitimate, wanted software that a user installs willingly; does not self-replicate"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:8c3c18e3', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ransomware”?", "options": ["Entering malicious SQL code into an input box to read, change or damage a database", "Fake emails, texts or websites that impersonate a trusted organisation to trick a user into revealing details", "Inventing a false scenario to persuade a victim into handing over information or access", "Encrypts a victim''s files and demands payment in exchange for the decryption key"]}'::jsonb, '{"answer": 3, "explain": "“Ransomware” means: Encrypts a victim''s files and demands payment in exchange for the decryption key"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:4ea3187a', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Spyware”?", "options": ["Secretly monitors a user''s activity and sends the information back to an attacker", "Capturing data as it travels across a network, especially an unsecured one", "Automatically trying huge numbers of password combinations until the correct one is found", "Encrypts a victim''s files and demands payment in exchange for the decryption key"]}'::jsonb, '{"answer": 0, "explain": "“Spyware” means: Secretly monitors a user''s activity and sends the information back to an attacker"}'::jsonb),
