('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:70a8d59f', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Phishing”?", "options": ["Encrypts a victim''s files and demands payment in exchange for the decryption key", "Fake emails, texts or websites that impersonate a trusted organisation to trick a user into revealing details", "Attaches itself to a file or program and spreads when a user runs the infected host file", "Manipulating a person, rather than a system, into revealing information or breaking security procedures"]}'::jsonb, '{"answer": 1, "explain": "“Phishing” means: Fake emails, texts or websites that impersonate a trusted organisation to trick a user into revealing details"}'::jsonb),
