('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:43d919fe', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Shouldering (shoulder surfing)”?", "options": ["Watching over someone''s shoulder as they type a password or enter other sensitive information", "Malware disguised as legitimate, wanted software that a user installs willingly; does not self-replicate", "Flooding a server with traffic so that it cannot respond to genuine users'' requests", "Encrypts a victim''s files and demands payment in exchange for the decryption key"]}'::jsonb, '{"answer": 0, "explain": "“Shouldering (shoulder surfing)” means: Watching over someone''s shoulder as they type a password or enter other sensitive information"}'::jsonb),
