('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:f6afdad9', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Denial of Service (DoS)”?", "options": ["Flooding a server with traffic so that it cannot respond to genuine users'' requests", "Encrypts a victim''s files and demands payment in exchange for the decryption key", "Automatically trying huge numbers of password combinations until the correct one is found", "Self-replicating malware that spreads across a network by itself, without any user action"]}'::jsonb, '{"answer": 0, "explain": "“Denial of Service (DoS)” means: Flooding a server with traffic so that it cannot respond to genuine users'' requests"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:38941bec', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Data interception”?", "options": ["Automatically trying huge numbers of password combinations until the correct one is found", "Manipulating a person, rather than a system, into revealing information or breaking security procedures", "Capturing data as it travels across a network, especially an unsecured one", "Encrypts a victim''s files and demands payment in exchange for the decryption key"]}'::jsonb, '{"answer": 2, "explain": "“Data interception” means: Capturing data as it travels across a network, especially an unsecured one"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:match:c4c09a42', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “SQL injection”?", "options": ["Capturing data as it travels across a network, especially an unsecured one", "Secretly monitors a user''s activity and sends the information back to an attacker", "Entering malicious SQL code into an input box to read, change or damage a database", "Inventing a false scenario to persuade a victim into handing over information or access"]}'::jsonb, '{"answer": 2, "explain": "“SQL injection” means: Entering malicious SQL code into an input box to read, change or damage a database"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:exam:75099d01', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the security method that monitors and filters the traffic passing between a network and the internet.</p>", "options": ["Encryption", "Firewall", "Anti-malware software", "Penetration testing"], "hint": "Focus on the key word ''traffic'' — only one of these methods is about what is allowed in and out of the network."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Firewall</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Firewall."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:exam:80d9fc69', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify the security method that scrambles data so that it cannot be understood if it is intercepted.</p>", "options": ["User access levels", "Encryption", "A firewall", "Physical security"], "hint": "The clue is ''scrambles data … cannot be understood'' — that points to one specific method."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Encryption</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Encryption."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:eddbf9fb', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "What is penetration testing?", "options": ["An unauthorised attack carried out by criminals that a company has never agreed to, and cannot see coming or control", "An authorised, simulated attack used to find weaknesses before real attackers do", "A tool that automatically writes strong passwords for every employee", "A backup process that copies data to a second location every night"]}'::jsonb, '{"answer": 1, "explain": "Penetration testing is a deliberate, authorised attack whose purpose is to find and report vulnerabilities so they can be fixed first."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:5d574ee0', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "Which task is carried out by anti-malware software?", "options": ["Filtering the network traffic that passes in and out of the network, according to a set of rules", "Scanning files and removing or quarantining software identified as malicious", "Scrambling data so it cannot be read without the correct key", "Controlling which doors an employee''s swipe card can open"]}'::jsonb, '{"answer": 1, "explain": "Anti-malware scans for malware and quarantines/removes it — filtering traffic is a firewall''s job and scrambling data is encryption."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:ca9316c5', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "What does a firewall mainly control?", "options": ["The traffic allowed to travel between a network and the internet", "The strength of every password chosen by the company''s employees", "The temperature inside the locked server room", "The order in which files are saved onto the hard drive"]}'::jsonb, '{"answer": 0, "explain": "A firewall monitors and filters network traffic against rules, blocking unauthorised connections — it does not manage passwords, cooling or storage."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:9e2ac320', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "A company gives most staff read-only access to the customer records, and only two managers read-and-write access. What kind of security measure is this?", "options": ["Encryption", "User access levels", "A brute-force attack", "Penetration testing"]}'::jsonb, '{"answer": 1, "explain": "Giving different users different rights (read-only vs read-write) is exactly what user access levels (permissions) means."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:c785cf6e', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "Which of these best describes what encryption does to data?", "options": ["It deletes the data so that nobody, including the owner, can ever recover it again", "It scrambles the data so it is meaningless to anyone without the key", "It copies the data to a backup server in a different building", "It makes the data download much faster over the network"]}'::jsonb, '{"answer": 1, "explain": "Encryption uses an algorithm and key to scramble data so that, even if intercepted, it cannot be understood without the correct key."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:663fc2fd', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "A login system locks an account for ten minutes after five wrong passwords in a row. Which attack is this designed to slow down?", "options": ["A phishing email scam", "A brute-force attack", "Data interception and theft", "Shouldering someone"]}'::jsonb, '{"answer": 1, "explain": "Locking the account after repeated failed attempts directly targets brute-force attacks, which depend on trying many password guesses quickly."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:01c9c167', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "Which measure most directly protects against a social engineering attack such as phishing?", "options": ["Installing a much more powerful and expensive firewall on the company''s main office network", "Training staff to recognise and question suspicious messages and requests", "Encrypting all of the files stored on the central server", "Fitting biometric locks to every door in the building"]}'::jsonb, '{"answer": 1, "explain": "Social engineering targets people, so staff training and awareness — not a technical tool — is the defence that actually helps against it."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:adb3c71f', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of physical security?", "options": ["A firewall configured to block all incoming connections from unknown addresses", "A locked server room that can only be entered with a swipe card", "A password policy requiring at least twelve characters", "Anti-malware software set to scan every file automatically"]}'::jsonb, '{"answer": 1, "explain": "A swipe-card-controlled locked room physically restricts access to the hardware — the others are all software or policy measures."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:c78afabf', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "Using a Caesar cipher with a key (shift) of 3, what does the word DOG become?", "options": ["GRJ", "AKD", "DOG", "HSK"]}'::jsonb, '{"answer": 0, "explain": "Shift each letter forward by 3: D→G, O→R, G→J, giving GRJ."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:5f251da9', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "Why is two-step (two-factor) verification stronger than a password on its own?", "options": ["It means the user never again has to remember any password, PIN or security question of any kind", "It needs a second factor, such as a phone code, that a password thief would not have", "It automatically makes the password longer every time it is typed", "It hides the login page so that attackers cannot find the website"]}'::jsonb, '{"answer": 1, "explain": "2FA adds a second factor the attacker is unlikely to have, so even a stolen password alone is not enough to get in."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:bbffe614', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "What is the main reason organisations keep regular backups as part of good security policy?", "options": ["To make the whole network connection run at a noticeably higher speed for every member of staff", "So that data can be restored after an attack such as ransomware, without paying", "To prevent employees from ever choosing a weak password again", "To stop any data from being intercepted while it travels across a network"]}'::jsonb, '{"answer": 1, "explain": "Backups let an organisation recover its data after ransomware or data loss, avoiding paying a ransom — they don''t affect speed, passwords or interception."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:mcq:93a323ab', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'mcq', 'mcq', 1, '{"question": "Which pairing correctly matches a threat to a method that limits it?", "options": ["Data interception → a biometric lock on the server-room door", "Brute-force attack → strong passwords plus account lockout", "Phishing → encrypting all of the files on the hard drive", "Malware infection → giving every user read-and-write access"]}'::jsonb, '{"answer": 1, "explain": "Strong passwords and account lockout directly defeat brute-force attacks; the other three pair a threat with a method that does not actually address it."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:99ce9dff', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "Penetration testing is carried out with the organisation''s permission to find weaknesses before real attackers do."}'::jsonb, '{"answer": true, "explain": "Correct — pen testing is an authorised, legal test whose purpose is to identify and report vulnerabilities so they can be fixed."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:a6b97f3b', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "A firewall scans files stored on the hard drive and removes any viruses it finds."}'::jsonb, '{"answer": false, "explain": "That is the job of anti-malware software. A firewall filters network traffic; it does not scan files for viruses."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:e06e053e', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "Anti-malware software only needs to be installed once and never needs updating."}'::jsonb, '{"answer": false, "explain": "New malware appears constantly, so the signature database must be updated regularly, or the software cannot recognise the newest threats."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:399f0e19', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "Encryption prevents data from ever being intercepted as it travels across a network."}'::jsonb, '{"answer": false, "explain": "Encryption does not stop interception — it makes the intercepted data unreadable without the key, so it is useless to the attacker."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:a091fa1d', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "Giving users only the access levels they need limits how far a compromised account can reach."}'::jsonb, '{"answer": true, "explain": "Correct — if an account is stolen, access levels mean the attacker can only reach what that account was permitted, not the whole system."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:2511e9a8', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "A longer, more varied password makes a brute-force attack take much longer to succeed."}'::jsonb, '{"answer": true, "explain": "Correct — more length and character variety means far more possible combinations to try, so brute force is much slower."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:8b1b64ea', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "A Caesar cipher is strong enough to protect real bank data because it is impossible to crack."}'::jsonb, '{"answer": false, "explain": "A Caesar cipher is very weak — there are only 25 possible shifts, so it is cracked almost instantly. It only demonstrates the idea of encryption."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tf:7879ea79', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tf', 'tf', 1, '{"question": "Staff training helps protect against social engineering attacks such as phishing."}'::jsonb, '{"answer": true, "explain": "Correct — social engineering targets people, so training them to recognise and question suspicious requests is the defence that works."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:3a95f181', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Why prevention needs layers", "reading": "<h4>No single defence stops every threat</h4>\n<ul>\n<li><strong>1.4.1</strong> covered the <strong>threats</strong> (malware, social engineering, brute force, DoS, data interception, SQL injection). This topic covers the <strong>defences</strong> that limit them.</li>\n<li>Each prevention method is good at stopping <strong>particular</strong> threats, but no single method stops them all. For example, a firewall filters network traffic but does nothing about a member of staff being tricked by a phishing phone call.</li>\n<li>So real systems use <strong>several methods together</strong> — often called a \"layered\" or \"defence in depth\" approach — so that if one layer is bypassed, others still protect the system.</li>\n</ul>\n<h4>The exam skill</h4>\n<ul>\n<li>The key skill for this topic is matching a <strong>defence to the threat it limits</strong>, and explaining <strong>how</strong> it does so — not just naming methods.</li>\n</ul>", "question": "Why do secure systems usually combine several different prevention methods?", "options": ["Because using more methods always makes a computer run faster over time", "Because no single method stops every threat, so layers cover each other''s gaps", "Because the law requires every business to install exactly five security tools", "Because one method is enough on its own if it is the newest one available"]}'::jsonb, '{"answer": 1, "explain": "Each method limits only particular threats, so combining them (defence in depth) means a threat that slips past one layer can still be stopped by another."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:b7baefe4', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Penetration testing — what it is", "reading": "<h4>Attacking your own system, on purpose and with permission</h4>\n<ul>\n<li><strong>Penetration testing</strong> (pen testing) is a deliberate, <strong>authorised</strong> attack on a system, carried out by specialists to find <strong>weaknesses (vulnerabilities)</strong> before a real attacker does.</li>\n<li>The testers try to break in using the same techniques a criminal would, then <strong>report</strong> the weaknesses they found so the organisation can <strong>fix them</strong>.</li>\n<li>The crucial point for the exam: it is <strong>legal and requested by the organisation itself</strong> — the goal is to identify and close gaps, not to cause harm or steal data.</li>\n</ul>", "question": "What is the main purpose of penetration testing?", "options": ["To permanently delete any data that an attacker might one day want to steal from the system", "To find weaknesses in a system so they can be fixed before a real attacker exploits them", "To flood a company''s own website with traffic to see how fast it runs", "To replace the need for any anti-malware software on the network"]}'::jsonb, '{"answer": 1, "explain": "Pen testing is an authorised, simulated attack whose whole point is to find and report vulnerabilities so the organisation can close them first."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:1f17674b', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Penetration testing — internal vs external", "reading": "<h4>Two viewpoints an attack can come from</h4>\n<ul>\n<li><strong>Internal testing</strong> simulates an attacker who already has some <strong>inside access</strong> — for example a disgruntled employee, or someone who has stolen a staff login. It checks how much damage could be done <strong>from inside</strong> the network.</li>\n<li><strong>External testing</strong> simulates an attacker with <strong>no inside knowledge or access</strong>, attacking from <strong>outside</strong> the organisation (over the internet) — testing the defences that face the outside world, such as the firewall.</li>\n<li>Running both gives a fuller picture: some weaknesses only matter to an outsider, others only become dangerous once an attacker is already inside (which is exactly why <strong>user access levels</strong> matter).</li>\n</ul>", "question": "What does internal penetration testing simulate?", "options": ["An attacker who has absolutely no prior knowledge of the system, and no access to any part of it whatsoever", "An attacker who already has some access from inside, such as a rogue employee or stolen login", "A hardware fault inside one of the company''s servers", "A power cut affecting the whole building at once"]}'::jsonb, '{"answer": 1, "explain": "Internal testing models a threat from inside the network (e.g. a malicious insider or a stolen account) to see how far that access could reach."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:6c281c53', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Anti-malware software", "reading": "<h4>Finding and removing malicious software</h4>\n<ul>\n<li><strong>Anti-malware</strong> (including antivirus) software <strong>scans</strong> files and the system, looking for <strong>malware</strong>.</li>\n<li>It recognises known malware by comparing files against a <strong>database of known malware signatures</strong>. When it finds a match, it <strong>quarantines</strong> (isolates) or <strong>removes/deletes</strong> the malicious file.</li>\n<li>It can also run in the background, checking files as they are opened or downloaded and <strong>warning</strong> the user about suspicious ones.</li>\n<li><strong>Why it must be kept up to date:</strong> new malware appears constantly, so the signature database must be updated regularly — out-of-date anti-malware cannot recognise the newest threats.</li>\n</ul>", "question": "Why must anti-malware software be kept up to date?", "options": ["Because updates make the computer''s hardware physically last much longer", "Because new malware appears all the time and out-of-date software cannot recognise it", "Because the software stops running completely after exactly one week without an update", "Because updates are the only way to change the desktop background colour"]}'::jsonb, '{"answer": 1, "explain": "Anti-malware spots threats by comparing them against a database of known malware, so it can only catch the latest threats if that database is regularly updated."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:3034536d', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Firewalls", "reading": "<h4>A filter between a network and the outside world</h4>\n<ul>\n<li>A <strong>firewall</strong> sits between a device or network and the internet, and <strong>monitors and filters</strong> the <strong>incoming and outgoing</strong> traffic that tries to pass through.</li>\n<li>It checks traffic against a set of <strong>rules</strong>, then <strong>allows</strong> traffic that is permitted and <strong>blocks</strong> traffic that is not — helping to keep out <strong>unauthorised access</strong> and unwanted connections.</li>\n<li>A firewall controls <strong>traffic</strong>; it is <strong>not</strong> the same as anti-malware. It does not scan files for viruses — the two do different jobs and are used together.</li>\n</ul>", "question": "What does a firewall do?", "options": ["It scans all of the files already saved on the computer''s hard drive and deletes any viruses that it finds", "It monitors and filters incoming and outgoing network traffic against a set of rules", "It encrypts every document so that it cannot be read without a key", "It makes automatic backup copies of important files onto a second drive"]}'::jsonb, '{"answer": 1, "explain": "A firewall''s job is to filter network traffic (in and out) using rules, blocking unauthorised connections — scanning files for viruses is the job of anti-malware."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:92e2f3b8', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "User access levels", "reading": "<h4>Not everyone should be able to see or change everything</h4>\n<ul>\n<li><strong>User access levels</strong> (permissions) control what each user is allowed to do with data and systems — for example <strong>read-only</strong>, <strong>read and write</strong>, or no access at all.</li>\n<li>Users are given only the access they actually need for their role. A student might read a resource but not edit it; only certain staff can change grades.</li>\n<li><strong>Why it matters:</strong> it prevents accidental or deliberate damage, and it <strong>limits how far an attack can reach</strong> — if one account is compromised, the attacker can only access what that account was allowed to, not the whole system.</li>\n</ul>", "question": "How do user access levels help if an attacker steals one employee''s login?", "options": ["They instantly and automatically delete the attacker''s own computer from a distance", "They limit the attacker to only what that one account was allowed to access", "They make the stolen password start working for every account in the company", "They guarantee the attacker can never read any file of any kind at all"]}'::jsonb, '{"answer": 1, "explain": "Access levels contain the damage: a compromised account can only reach the data and actions it was permitted, so the attacker cannot automatically reach everything."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:e57521a0', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Passwords — strong passwords", "reading": "<h4>Making a password hard to guess or crack</h4>\n<ul>\n<li>A <strong>strong password</strong> is <strong>long</strong> and mixes <strong>upper and lower case letters, numbers and symbols</strong>, and is not an obvious word, name or date.</li>\n<li>Each extra character and character type massively increases the number of <strong>possible combinations</strong>, so a <strong>brute-force attack</strong> (trying combinations automatically) takes far longer — often long enough to be impractical.</li>\n<li>Passwords should also be <strong>unique</strong> to each account: if the same password is reused everywhere, one leak exposes every account.</li>\n</ul>", "question": "Why does making a password longer and more varied help protect an account?", "options": ["It makes the whole computer start up and shut down noticeably more quickly each and every morning without fail", "It hugely increases the number of possible combinations, so a brute-force attack takes far longer", "It stops the user from ever forgetting the password again", "It automatically encrypts every file the user owns"]}'::jsonb, '{"answer": 1, "explain": "More length and more character types mean far more possible combinations to try, so an automated brute-force attack takes much longer to succeed."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:24b407f9', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Passwords — extra protection", "reading": "<h4>Backing up a password with more than just the password</h4>\n<ul>\n<li><strong>Account lockout:</strong> the system locks an account (or adds a delay) after a set number of <strong>failed login attempts</strong>. This directly slows or stops a brute-force attack, which relies on trying many guesses quickly.</li>\n<li><strong>Two-step / two-factor verification (2FA):</strong> as well as the password, the user must provide a second thing — usually a <strong>code sent to a separate device</strong> such as their phone. Even if an attacker steals the password, they still cannot log in without that second factor.</li>\n<li>These protect against the ways a password alone can fail — being guessed, cracked, or even stolen.</li>\n</ul>", "question": "How does two-step (two-factor) verification protect an account even if the password is stolen?", "options": ["It quietly changes the account''s password back to the previous one automatically every single night", "The attacker still needs a second factor, such as a code sent to the user''s own phone", "It makes the account impossible for the real owner to ever log in to as well", "It hides the account from the internet so no data ever leaves the device"]}'::jsonb, '{"answer": 1, "explain": "2FA requires a second factor the attacker does not have (e.g. a code on the user''s phone), so a stolen password on its own is not enough to log in."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:4c0a3644', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Encryption — the principle", "reading": "<h4>Scrambling data so intercepted data is useless</h4>\n<ul>\n<li><strong>Encryption</strong> uses an <strong>algorithm</strong> and a <strong>key</strong> to <strong>scramble</strong> data into a form that cannot be understood.</li>\n<li>Only someone with the correct <strong>key</strong> can <strong>decrypt</strong> it back into the original, readable data.</li>\n<li><strong>What it does and does not do:</strong> encryption does <strong>not stop</strong> data being intercepted or stolen — but if intercepted, the data is <strong>meaningless</strong> to the attacker without the key. This is why it is the main defence against <strong>data interception</strong>, and why it protects data on a lost or stolen device too.</li>\n</ul>", "question": "What does encryption actually achieve if an attacker intercepts the data anyway?", "options": ["It physically prevents the data from ever leaving the sender''s own computer in the first place", "The intercepted data is scrambled and meaningless without the correct decryption key", "It automatically reports the attacker''s location to the police", "It makes a second, identical copy of the data as a backup"]}'::jsonb, '{"answer": 1, "explain": "Encryption doesn''t prevent interception; it makes the intercepted data unreadable, so it is useless to anyone who does not hold the key."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:d17c8abb', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Encryption — a Caesar cipher example", "reading": "<h4>A very simple cipher that shows the idea</h4>\n<ul>\n<li>A <strong>Caesar cipher</strong> is a simple form of encryption: <strong>shift every letter</strong> along the alphabet by a fixed number of places — the number of places is the <strong>key</strong>.</li>\n<li>Example with a key of <strong>1</strong>: A→B, B→C, … so <strong>HELLO</strong> becomes <strong>IFMMP</strong>. To decrypt, shift each letter back by the same key.</li>\n<li>Letters near the end wrap around: with a key of 1, Z→A.</li>\n<li><strong>Why real systems don''t use it:</strong> a Caesar cipher is extremely weak — there are only 25 possible shifts, so it can be cracked almost instantly. It is only useful for showing how encryption works; real encryption uses far more complex keys and algorithms.</li>\n</ul>", "question": "Using a Caesar cipher with a key (shift) of 1, what does the word CAT become?", "options": ["DBU", "BZS", "CAT", "EDV"]}'::jsonb, '{"answer": 0, "explain": "Shift each letter forward by 1: C→D, A→B, T→U, giving DBU."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:62ba2426', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Physical security", "reading": "<h4>Protecting the hardware itself</h4>\n<ul>\n<li>Not every attack happens over a network — some need the attacker to be <strong>physically present</strong>. <strong>Physical security</strong> protects the computers, servers and the rooms they are in.</li>\n<li>Common methods: <strong>locks</strong> on doors and equipment, <strong>keypad / swipe-card / keycard</strong> entry, <strong>biometric</strong> entry (fingerprint or face), <strong>CCTV</strong>, <strong>alarms</strong>, <strong>security staff</strong>, and keeping servers in a <strong>locked server room</strong>.</li>\n<li>This limits threats such as <strong>hardware theft</strong>, tampering, or someone walking up to a machine — and works alongside digital defences, not instead of them.</li>\n</ul>", "question": "Which of these is an example of physical security?", "options": ["Installing anti-malware software on every computer in the office", "A biometric fingerprint lock on the door of the server room", "Choosing a long, complex password for an online account", "Encrypting the data before it is sent across the network"]}'::jsonb, '{"answer": 1, "explain": "A biometric door lock physically controls who can reach the hardware — the other options are all digital/software measures, not physical security."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:2d6c0cb5', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Network policies & staff training", "reading": "<h4>The human layer technology can''t cover</h4>\n<ul>\n<li>Because people are often the weakest link, organisations use <strong>network / acceptable-use policies</strong>: written rules about passwords, what software may be installed, and how systems may be used.</li>\n<li><strong>Staff training</strong> teaches people to <strong>recognise</strong> phishing emails and other <strong>social engineering</strong> tricks, and to follow procedures such as verifying a caller before sharing information — the one thing a firewall or anti-malware cannot do.</li>\n<li>Sensible policy also includes keeping <strong>backups</strong>, so that if ransomware or another attack does strike, data can be <strong>restored</strong> without paying a ransom.</li>\n</ul>", "question": "Why is staff training an important security measure alongside technical ones?", "options": ["It completely replaces the need for a firewall, anti-malware software and encryption all at the same time", "It helps people recognise social engineering, such as phishing, which technical tools cannot stop", "It makes the office internet connection noticeably faster for everyone", "It is the only way to make backups of important company data"]}'::jsonb, '{"answer": 1, "explain": "Social engineering targets people, not software, so only awareness and training help staff spot and resist it — technical tools can''t stop a person being tricked."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:learn:82e07621', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'learn', 'mcq', 1, '{"readingTitle": "Matching the defence to the threat", "reading": "<h4>The mapping the exam keeps testing</h4>\n<ul>\n<li><strong>Anti-malware</strong> → detects and removes <strong>malware</strong> (viruses, worms, trojans, ransomware, spyware).</li>\n<li><strong>Firewall</strong> → blocks <strong>unauthorised access</strong> and unwanted traffic trying to enter or leave the network.</li>\n<li><strong>Encryption</strong> → makes <strong>intercepted data</strong> unreadable, defeating data interception/theft.</li>\n<li><strong>Strong passwords + account lockout</strong> → defeat <strong>brute-force</strong> attacks.</li>\n<li><strong>Two-step verification</strong> → protects against a <strong>stolen or guessed password</strong>.</li>\n<li><strong>User access levels</strong> → limit the <strong>damage/spread</strong> of a compromised account or a malicious insider.</li>\n<li><strong>Physical security</strong> → stops <strong>theft</strong>, tampering and shouldering by someone physically present.</li>\n<li><strong>Staff training / anti-phishing</strong> → resists <strong>social engineering</strong>.</li>\n<li><strong>Penetration testing</strong> → finds <strong>all kinds of weaknesses</strong> first, so they can be fixed.</li>\n</ul>", "question": "Which prevention method most directly protects against data being read if it is intercepted while travelling across a network?", "options": ["A strong, complex and regularly changed password on the sender''s own user account", "Encryption, which scrambles the data so it is unreadable without the key", "A biometric lock on the door of the office", "Anti-malware software scanning the hard drive"]}'::jsonb, '{"answer": 1, "explain": "Encryption is the defence aimed squarely at interception — the data can still be captured, but it is meaningless without the key."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:misc:c812c581', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a firewall stops viruses and other malware, just like antivirus software does.</p><p><strong>✅ The correct idea:</strong> A <strong>firewall</strong> filters network <strong>traffic</strong> against rules — it decides what is allowed in and out of the network. It does <strong>not</strong> scan files for viruses; that is <strong>anti-malware''s</strong> job. They do different jobs and are used together.</p>", "question": "What is the difference between a firewall and anti-malware software?", "options": ["There is no real difference at all — they are simply two different names for exactly the same program", "A firewall filters network traffic; anti-malware scans files for and removes malware", "A firewall scans files, while anti-malware only controls door locks", "A firewall encrypts data, while anti-malware chooses passwords"]}'::jsonb, '{"answer": 1, "explain": "A firewall controls what traffic may pass in and out of the network; anti-malware scans files and removes malicious ones — two separate roles."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:misc:48530549', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing that encryption stops data from being stolen or intercepted in the first place.</p><p><strong>✅ The correct idea:</strong> Encryption does <strong>not</strong> prevent data being intercepted or copied. What it does is <strong>scramble</strong> the data so that, if intercepted, it is <strong>meaningless</strong> without the key. The attacker can still capture it — they just cannot understand it.</p>", "question": "If an attacker intercepts encrypted data, what happens?", "options": ["The data is automatically and permanently deleted before the attacker is able to save it anywhere at all", "The attacker captures scrambled data that is meaningless without the decryption key", "The attacker is immediately blocked from the network by the firewall", "The data turns back into plain text as soon as it is intercepted"]}'::jsonb, '{"answer": 1, "explain": "Encryption doesn''t block interception; it ensures that intercepted data is unreadable without the key, so it is useless to the attacker."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:misc:a6cdf40f', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming penetration testing is an illegal attack carried out by criminals.</p><p><strong>✅ The correct idea:</strong> Penetration testing is <strong>authorised</strong> — the organisation asks for it. Testers use the same techniques as attackers, but the goal is to <strong>find and report weaknesses</strong> so they can be fixed, not to cause harm or steal data.</p>", "question": "Why is penetration testing not the same as a criminal attack, even though similar techniques are used?", "options": ["Because penetration testers are never able to actually break into anything at all", "Because it is authorised by the organisation and aims to find and fix weaknesses", "Because it can only ever be done on computers that are switched off", "Because it does not use any real hacking techniques whatsoever"]}'::jsonb, '{"answer": 1, "explain": "The techniques may be similar, but pen testing is requested by the organisation and its purpose is to identify and close vulnerabilities safely."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:misc:d9322dc7', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a strong password alone is enough to keep an account completely safe.</p><p><strong>✅ The correct idea:</strong> A strong password defeats <strong>guessing and brute force</strong>, but it does nothing if the user is <strong>tricked into revealing it</strong> (phishing), has it captured by a <strong>keylogger</strong>, or is watched typing it (shouldering). That is why <strong>two-step verification</strong> and <strong>staff training</strong> matter too.</p>", "question": "Why is a strong password not enough on its own to secure an account?", "options": ["Because even the strongest passwords always stop working completely after just a single day of being used", "Because it can still be phished, keylogged or shoulder-surfed, so extra measures are needed", "Because long passwords are actually easier to guess than short ones", "Because passwords have no effect on brute-force attacks at all"]}'::jsonb, '{"answer": 1, "explain": "A strong password resists guessing, but it can still be stolen or given away, so 2FA and training are needed alongside it."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:misc:9113f509', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing physical security has nothing to do with keeping data safe.</p><p><strong>✅ The correct idea:</strong> If an attacker can <strong>physically reach</strong> a computer or server, many digital defences can be bypassed — they could <strong>steal the hardware</strong>, tamper with it, or watch someone type a password. <strong>Locks, keycards, biometrics and CCTV</strong> protect against exactly these physical routes to the data.</p>", "question": "Why does physical security matter for protecting data?", "options": ["Because software and networks can never actually be attacked in any real way, only the physical hardware can be", "Because someone who can physically reach a machine can steal it or tamper with it", "Because CCTV cameras encrypt all of the company''s files automatically", "Because physical locks are the only security a computer ever needs"]}'::jsonb, '{"answer": 1, "explain": "Physical access can defeat digital protections — stolen hardware or a watched password is a real breach, so physical security is part of protecting data."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:misc:5596bc70', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mixing up user access levels with encryption, thinking both simply ''protect the files''.</p><p><strong>✅ The correct idea:</strong> They protect files in <strong>different ways</strong>. <strong>Access levels</strong> control <strong>who is allowed</strong> to open or change a file. <strong>Encryption</strong> scrambles the file''s <strong>contents</strong> so it is unreadable without a key. A file can use both: only certain users may open it, and it is scrambled if it is stolen.</p>", "question": "How do user access levels differ from encryption?", "options": ["They are really two completely identical security measures that simply happen to have two different names", "Access levels control who may use a file; encryption scrambles the file''s contents", "Access levels scramble data, while encryption chooses who can log in", "Neither has anything to do with protecting files"]}'::jsonb, '{"answer": 1, "explain": "Access levels decide who is permitted to open or edit data; encryption makes the data itself unreadable without a key — different, complementary protections."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tips:8d732178', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tips', 'mcq', 1, '{"readingTitle": "tip — Always name the threat a method stops — and how", "reading": "<p>The single most common question style in this topic gives you a threat (or a scenario) and asks for a suitable prevention method. A one-word method name rarely gets full marks — the mark scheme wants the <strong>method + the threat it addresses + how it helps</strong>.</p>\n\n<p><strong>❌ 1 mark:</strong> \"Use encryption.\"</p>\n<p><strong>✅ 2–3 marks:</strong> \"Use <strong>encryption</strong> <strong>(method)</strong>, which scrambles the data using a key <strong>(how)</strong>, so that if it is <strong>intercepted</strong> on the network it cannot be understood without the key <strong>(threat addressed)</strong>.\"</p>\n\n<p><strong>Quick self-check:</strong> for every prevention method you name, silently finish the sentence \"…which stops/limits ___ by ___.\" If you can''t, add the detail before moving on.</p>", "question": "A 3-mark question asks how a company could protect data sent over a network. A student just writes ''use encryption''. What is most likely missing?", "options": ["Nothing at all — the phrase ''use encryption'' completely answers any 3-mark question on its own", "How encryption works and which threat it addresses (unreadable if intercepted)", "The exact price of encryption software from three different suppliers", "A drawing of the network cables used in the office"]}'::jsonb, '{"answer": 1, "explain": "Naming the method alone is about 1 mark; the extra marks come from explaining how it works and the specific threat (interception) it addresses."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tips:d3aee3ac', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tips', 'mcq', 1, '{"readingTitle": "explain — Firewall vs anti-malware vs encryption — don''t mix them up", "reading": "<p>Questions love to check whether you really know which method does which job, because students often blur the three together. Keep them separate:</p>\n<ul>\n<li><strong>Firewall</strong> — filters network <strong>traffic</strong> (what is allowed in/out). Stops unauthorised access.</li>\n<li><strong>Anti-malware</strong> — scans <strong>files</strong> and removes <strong>malware</strong>. Stops viruses, worms, trojans, ransomware, spyware.</li>\n<li><strong>Encryption</strong> — scrambles <strong>data</strong> so intercepted data is unreadable. Stops data interception being useful.</li>\n</ul>\n<p>If a question says \"scan and remove a virus\" the answer is anti-malware, never a firewall. If it says \"so intercepted data can''t be read\" the answer is encryption, never anti-malware.</p>", "question": "A question asks which method would ''scan the computer and remove a trojan that had been downloaded''. What is the correct method?", "options": ["A firewall, because it automatically blocks every single download coming from the internet", "Anti-malware software, because it scans files and removes malware", "Encryption, because it scrambles the trojan''s code", "User access levels, because they stop downloads completely"]}'::jsonb, '{"answer": 1, "explain": "Scanning for and removing malware such as a trojan is anti-malware''s job — a firewall filters traffic and encryption scrambles data."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:tips:edc3a733', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — The structured ''threat + prevention'' extended question", "reading": "<p>A longer question on this topic often asks you to <strong>identify several threats and describe how each can be prevented</strong> — for example three threats, each with a prevention method, worth several marks in total.</p>\n\n<p><strong>How it is marked:</strong> the marks are split across the threat–prevention <strong>pairs</strong>. For each pair you typically earn marks for (1) naming a valid, <strong>distinct</strong> threat and (2) <strong>describing</strong> a prevention that genuinely addresses <em>that</em> threat.</p>\n\n<p><strong>Where students lose marks:</strong></p>\n<ul>\n<li>Giving three threats but the <strong>same</strong> prevention for all of them (or three preventions that don''t match the threats).</li>\n<li>Only <strong>naming</strong> a prevention (\"a firewall\") instead of <strong>describing</strong> what it does.</li>\n<li>Repeating the same threat twice in slightly different words — each pair must be <strong>different</strong>.</li>\n</ul>\n<p><strong>Safe approach:</strong> pick three clearly different threats (e.g. malware, brute force, data interception) and give each its natural, well-described defence (anti-malware; strong passwords + lockout; encryption).</p>", "question": "On a ''identify three threats and describe how to prevent each'' question, what is a common way students lose marks?", "options": ["Choosing three clearly different threats, each one with its own separate matching prevention method", "Naming a prevention without describing it, or repeating the same threat twice", "Writing in full sentences instead of single words", "Describing exactly how each prevention method works in detail"]}'::jsonb, '{"answer": 1, "explain": "Marks come from distinct threat–prevention pairs that are described, so just naming a method or repeating a threat wastes the marks on offer."}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:58055d38', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "_____ testing is an authorised, simulated attack used to find weaknesses in a system before a real attacker does.", "blankOptions": {"B1": ["penetration", "firewall", "code", "brute-force"]}}'::jsonb, '{"blanks": {"B1": "penetration"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:91cfe677', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "A _____ monitors and filters the traffic passing between a network and the internet, blocking connections that are not allowed.", "blankOptions": {"B1": ["signatures", "firewall", "shifting", "code"]}}'::jsonb, '{"blanks": {"B1": "firewall"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:b7ea8fb0', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "Anti-malware software recognises known malware by comparing files against a database of known _____.", "blankOptions": {"B1": ["firewall", "penetration", "brute-force", "signatures"]}}'::jsonb, '{"blanks": {"B1": "signatures"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:413f53bc', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "_____ scrambles data using an algorithm and a key, so that intercepted data cannot be understood without the key.", "blankOptions": {"B1": ["signatures", "brute-force", "penetration", "encryption"]}}'::jsonb, '{"blanks": {"B1": "encryption"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:d8dd119f', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "User access _____ control what each person is allowed to do with data, such as read-only or read-and-write.", "blankOptions": {"B1": ["signatures", "encryption", "levels", "shifting"]}}'::jsonb, '{"blanks": {"B1": "levels"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:9d779bdd', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "Locking an account after several failed login attempts is designed to slow down a _____ attack.", "blankOptions": {"B1": ["brute-force", "signatures", "code", "shifting"]}}'::jsonb, '{"blanks": {"B1": "brute-force"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:da3c19aa', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "Two-step verification asks for a second factor, such as a _____ sent to the user''s phone, as well as the password.", "blankOptions": {"B1": ["signatures", "levels", "firewall", "code"]}}'::jsonb, '{"blanks": {"B1": "code"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:fib:92296b9b', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'fib', 'fib', 1, '{"question": "A Caesar cipher encrypts a message by _____ each letter along the alphabet by a fixed key.", "blankOptions": {"B1": ["firewall", "encryption", "shifting", "penetration"]}}'::jsonb, '{"blanks": {"B1": "shifting"}}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:822ec533', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Penetration testing”?", "options": ["An authorised, simulated attack used to find weaknesses so they can be fixed before a real attacker exploits them", "Written rules setting out how systems, passwords and software may be used in an organisation", "Scans files, detects malware using a database of known signatures, and quarantines or removes it", "Control what each user may do with data (e.g. read-only or read-write), limiting the reach of any one account"]}'::jsonb, '{"answer": 0, "explain": "“Penetration testing” means: An authorised, simulated attack used to find weaknesses so they can be fixed before a real attacker exploits them"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:424d7afe', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Anti-malware software”?", "options": ["Scans files, detects malware using a database of known signatures, and quarantines or removes it", "Written rules setting out how systems, passwords and software may be used in an organisation", "A simple encryption method that shifts each letter along the alphabet by a fixed key", "Teaches people to recognise phishing and other social engineering so they are not tricked"]}'::jsonb, '{"answer": 0, "explain": "“Anti-malware software” means: Scans files, detects malware using a database of known signatures, and quarantines or removes it"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:0ba61986', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Firewall”?", "options": ["Protects the hardware itself using locks, keycards, biometrics, CCTV or a locked server room", "Scrambles data using an algorithm and a key so that, if intercepted, it cannot be understood", "Monitors and filters incoming and outgoing network traffic against a set of rules", "Teaches people to recognise phishing and other social engineering so they are not tricked"]}'::jsonb, '{"answer": 2, "explain": "“Firewall” means: Monitors and filters incoming and outgoing network traffic against a set of rules"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:00c3d4dc', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “User access levels”?", "options": ["Control what each user may do with data (e.g. read-only or read-write), limiting the reach of any one account", "Requires a second factor, such as a code sent to a phone, in addition to the password", "An authorised, simulated attack used to find weaknesses so they can be fixed before a real attacker exploits them", "Scrambles data using an algorithm and a key so that, if intercepted, it cannot be understood"]}'::jsonb, '{"answer": 0, "explain": "“User access levels” means: Control what each user may do with data (e.g. read-only or read-write), limiting the reach of any one account"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:f0f9c603', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Strong password”?", "options": ["A simple encryption method that shifts each letter along the alphabet by a fixed key", "A long, varied, unique password that greatly increases the combinations a brute-force attack must try", "Scans files, detects malware using a database of known signatures, and quarantines or removes it", "Teaches people to recognise phishing and other social engineering so they are not tricked"]}'::jsonb, '{"answer": 1, "explain": "“Strong password” means: A long, varied, unique password that greatly increases the combinations a brute-force attack must try"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:6bcb7633', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Account lockout”?", "options": ["An authorised, simulated attack used to find weaknesses so they can be fixed before a real attacker exploits them", "A long, varied, unique password that greatly increases the combinations a brute-force attack must try", "Protects the hardware itself using locks, keycards, biometrics, CCTV or a locked server room", "Locks an account after a set number of failed logins to slow or stop a brute-force attack"]}'::jsonb, '{"answer": 3, "explain": "“Account lockout” means: Locks an account after a set number of failed logins to slow or stop a brute-force attack"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:20383e18', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Two-step verification”?", "options": ["A long, varied, unique password that greatly increases the combinations a brute-force attack must try", "An authorised, simulated attack used to find weaknesses so they can be fixed before a real attacker exploits them", "Requires a second factor, such as a code sent to a phone, in addition to the password", "Scrambles data using an algorithm and a key so that, if intercepted, it cannot be understood"]}'::jsonb, '{"answer": 2, "explain": "“Two-step verification” means: Requires a second factor, such as a code sent to a phone, in addition to the password"}'::jsonb)
